import json
import uuid

# --- State persistence (simplified; use a database in production) ---
PENDING_APPROVALS: dict[str, dict] = {}

def suspend_for_approval(
    run_id: str,
    messages: list,
    pending_tool_call: dict,
) -> str:
    """
    Serialize the conversation state and the pending tool call.
    Returns an approval_token the caller can store.
    """
    approval_token = str(uuid.uuid4())
    PENDING_APPROVALS[approval_token] = {
        "run_id": run_id,
        "messages": messages,       # full conversation so far
        "pending_tool": pending_tool_call,  # the call awaiting approval
        "status": "pending",
    }
    return approval_token

def resume_with_decision(approval_token: str, approved: bool, note: str = "") -> dict | None:
    """
    Called by the approval handler (webhook, Slack bot, UI).
    Returns the saved state so the caller can resume the agent.
    """
    record = PENDING_APPROVALS.get(approval_token)
    if record is None:
        return None
    record["status"] = "approved" if approved else "rejected"
    record["reviewer_note"] = note
    return record

# --- Agent loop with async HITL ---
import anthropic
client = anthropic.Anthropic()

REQUIRES_APPROVAL = {"issue_refund", "send_email", "delete_record"}

def run_agent_async_hitl(user_request: str, system: str, tools: list, dispatch: dict) -> dict:
    run_id = str(uuid.uuid4())
    messages = [{"role": "user", "content": user_request}]

    for _ in range(15):
        import anthropic as _a
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001", max_tokens=512,
            system=system, tools=tools, messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "result": block.input}

        if not tool_calls:
            return {"status": "stuck"}

        results = []
        for block in tool_calls:
            if block.name in REQUIRES_APPROVAL:
                # Suspend: serialize state and return a token
                token = suspend_for_approval(
                    run_id=run_id,
                    messages=messages,
                    pending_tool_call={"name": block.name, "id": block.id, "input": block.input},
                )
                # In production: send `token` to a Slack/email approval queue.
                # Here: simulate immediate approval for demo purposes.
                print(f"[ASYNC HITL] Approval required for: {block.name}({block.input})")
                print(f"[ASYNC HITL] Token: {token}")
                record = resume_with_decision(token, approved=True, note="Auto-approved in demo")
                if not record["status"] == "approved":
                    result = json.dumps({"ok": False, "error": "Rejected by reviewer."})
                else:
                    fn = dispatch.get(block.name)
                    result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            else:
                fn = dispatch.get(block.name)
                result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})
    return {"status": "max_iterations"}

# Key insight: `messages` is the full serializable conversation state.
# Suspending means saving `messages` + the pending tool call to a database.
# Resuming means loading `messages`, appending the approved/rejected tool result,
# and continuing the loop with a new API call.
